const q=$input.item.json.query||{};
const code=q.code;
const state=q.state||'setup';
const page=state==='dashboard'?'dashboard.html':'setup.html';
const base='https://ephermal.app';

if(!code){
  return[{json:{redirectUrl:`${base}/${page}?meta_error=missing_code`}}];
}

const appId=$env.META_APP_ID;
const appSecret=$env.META_APP_SECRET;
const callbackUrl=$env.META_CALLBACK_URL||'https://jamhich.de/webhook/ephermal/meta/callback';

if(!appId||!appSecret){
  return[{json:{redirectUrl:`${base}/${page}?meta_error=server_not_configured`}}];
}

// Exchange code for access token
const tokenRes=await fetch(`https://graph.facebook.com/v19.0/oauth/access_token?client_id=${appId}&redirect_uri=${encodeURIComponent(callbackUrl)}&client_secret=${appSecret}&code=${code}`);
const tokenData=await tokenRes.json();

if(tokenData.error||!tokenData.access_token){
  const msg=encodeURIComponent((tokenData.error&&tokenData.error.message)||'token_exchange_failed');
  return[{json:{redirectUrl:`${base}/${page}?meta_error=${msg}`}}];
}

const token=tokenData.access_token;

// Fetch ad accounts
const accRes=await fetch(`https://graph.facebook.com/v19.0/me/adaccounts?fields=name,account_id&limit=50&access_token=${token}`);
const accData=await accRes.json();
const accounts=(accData.data||[]).map(a=>({id:a.id,name:a.name}));

const redirectUrl=`${base}/${page}?meta_token=${encodeURIComponent(token)}&meta_accounts=${encodeURIComponent(JSON.stringify(accounts))}`;
return[{json:{redirectUrl}}];
